import React, { useState, useEffect } from 'react';
import './style.css';
const App = () => {
  const [rooms, setRooms] = useState([{ name: 'Room 1' }, { name: 'Room 2' }]);
  const [messages, setMessages] = useState([{ room: 'Room 1', user: 'User 1', text: 'Hello World!' }]);
  const [searchTerm, setSearchTerm] = useState('');
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <header className="bg-[#C06C88] p-4 flex items-center justify-between">
        <h1 className="text-lg">{rooms[0].name}</h1>
        <div className="flex items-center">
          <input
            type="search"
            className="bg-transparent border-none py-2 pl-4 outline-none focus:ring-0"
            placeholder="Search users"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button className="bg-[#C06C88] px-4 py-2 rounded">Search</button>
        </div>
      </header>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4">
        {rooms.map((room, index) => (
          <div key={index} className="bg-[#090a0f] p-4 rounded">
            <h2 className="text-lg">{room.name}</h2>
            <ul>
              {messages
                .filter((message) => message.room === room.name || (searchTerm === '' ? true : message.user.includes(searchTerm)))
                .map((message, index) => (
                  <li key={index} className="py-2">
                    <span className="mr-2">{message.user}: </span>
                    <span className="text-sm">{message.text}</span>
                  </li>
                ))}
            </ul>
          </div>
        ))}
      </div>
    </div>
  );
};
export default App;
